184	        >
185	          {project.name}
186	        </p>
187	      )}
188	
189	      {/* 3. Version heading */}
190	      <h1
191	        className="text-[42px] font-bold tracking-tight text-foreground leading-[1.1]"
192	        style={{ fontFamily: "var(--font-raleway)" }}
193	      >
194	        {sr.version}
