1	"use client";
2	
3	import { useMemo } from "react";
4	import useSWR from "swr";
5	import Link from "next/link";
6	import { useRouter } from "next/navigation";
7	import { marked } from "marked";
8	import {
9	  releases as releasesApi,
10	  sources as sourcesApi,
11	  semanticReleases as srApi,
12	  projects as projectsApi,
13	} from "@/lib/api/client";
14	import { ProviderBadge } from "@/components/ui/provider-badge";
15	import { VersionChip } from "@/components/ui/version-chip";
16	import type { SemanticRelease, Source, Project } from "@/lib/api/types";
17	import { ArrowLeft, ExternalLink } from "lucide-react";
18	import { useTranslation } from "@/lib/i18n/context";
19	
20	import { timeAgo } from "@/lib/format";
21	import { getPathSegment } from "@/lib/path";
22	
23	/* ------------------------------------------------------------------ */
24	/*  Helpers                                                            */
25	/* ------------------------------------------------------------------ */
26	
27	/** Convert changelog to HTML via markdown parser.
28	 *  `marked` handles mixed markdown+HTML, so we always parse. */
29	function changelogToHtml(raw: string): string {
30	  return marked.parse(raw, { async: false }) as string;
31	}
32	
33	function getProviderUrl(
34	  provider: string,
35	  repository: string,
36	  version: string
37	): string | null {
38	  switch (provider) {
39	    case "github":
40	      return `https://github.com/${repository}/releases/tag/${version}`;
41	    case "dockerhub":
42	      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
43	    case "ecr-public":
44	      return `https://gallery.ecr.aws/${repository}`;
45	    case "gitlab":
46	      return `https://gitlab.com/${repository}/-/releases/${version}`;
47	    case "pypi":
48	      return `https://pypi.org/project/${repository}/${encodeURIComponent(version)}/`;
49	    case "npm":
50	      return `https://www.npmjs.com/package/${repository}/v/${encodeURIComponent(version)}`;
51	    default:
52	      return null;
53	  }
54	}
55	
56	function getProviderLabel(provider: string): string {
57	  switch (provider) {
58	    case "github":
59	      return "GitHub";
60	    case "dockerhub":
61	      return "Docker Hub";
62	    case "ecr-public":
63	      return "ECR Public";
64	    case "gitlab":
65	      return "GitLab";
66	    case "pypi":
67	      return "PyPI";
68	    case "npm":
69	      return "npm";
70	    default:
71	      return provider;
72	  }
73	}
74	
75	/* ------------------------------------------------------------------ */
76	/*  Component                                                          */
77	/* ------------------------------------------------------------------ */
78	
79	export function ReleaseDetail() {
80	  const { t } = useTranslation();
81	  const router = useRouter();
82	  // Read ID from URL path — useParams() returns stale "0" in static export
83	  const id = getPathSegment(1); // /releases/{id}
84	  /* Fetch release */
85	  const { data: releaseData, isLoading } = useSWR(`release-${id}`, () =>
86	    releasesApi.get(id)
87	  );
88	
89	  const release = releaseData?.data;
90	
91	  /* Fetch source info once we have the release */
92	  const { data: sourceData } = useSWR(
93	    release ? `source-${release.source_id}` : null,
94	    () => (release ? sourcesApi.get(release.source_id) : null)
95	  );
96	  const source: Source | undefined = sourceData?.data;
97	
98	  /* Fetch project info once we have the source */
99	  const { data: projectData } = useSWR(
100	    source ? `project-${source.project_id}` : null,
101	    () => (source ? projectsApi.get(source.project_id) : null)
102	  );
103	  const project: Project | undefined = projectData?.data;
104	
105	  /* Fetch linked semantic releases (via project) */
106	  const { data: srData } = useSWR(
107	    source ? `sr-for-release-${id}` : null,
108	    async () => {
109	      if (!source) return [];
110	      const res = await srApi.list(source.project_id, 1).catch(() => null);
111	      if (!res?.data) return [];
112	      /* Filter semantic releases whose version matches this release version */
113	      return res.data.filter((sr: SemanticRelease) => sr.version === release?.version);
114	    }
115	  );
116	
117	  const linkedSRs: SemanticRelease[] = srData ?? [];
118	
119	  /* Memoize changelog HTML conversion */
120	  const changelogHtml = useMemo(() => {
121	    const raw = release?.raw_data?.changelog;
122	    if (!raw) return null;
123	    return changelogToHtml(String(raw));
124	  }, [release?.raw_data?.changelog]);
125	
126	  /* Loading state */
127	  if (isLoading) {
128	    return (
129	      <div
130	        className="py-16 text-center"
131	        style={{
132	          fontFamily: "var(--font-dm-sans)",
133	          fontSize: "13px",
134	          color: "var(--text-secondary)",
135	        }}
136	      >
137	        {t("releases.loading")}
138	      </div>
139	    );
140	  }
141	
142	  if (!release) {
143	    return (
144	      <div className="py-16 text-center">
145	        <p
146	          style={{
147	            fontFamily: "var(--font-raleway)",
148	            fontStyle: "italic",
149	            fontSize: "15px",
150	            color: "var(--text-muted)",
151	          }}
152	        >
153	          {t("releases.notFound")}
154	        </p>
155	      </div>
156	    );
157	  }
158	
159	  return (
160	    <div className="space-y-8">
161	      {/* Back link */}
162	      <button
163	        onClick={() => window.history.length > 1 ? router.back() : router.push("/releases")}
164	        className="inline-flex items-center gap-1.5 transition-colors hover:opacity-70 cursor-pointer"
165	        style={{
166	          fontFamily: "var(--font-dm-sans)",
167	          fontSize: "13px",
168	          color: "var(--text-secondary)",
169	        }}
170	      >
171	        <ArrowLeft size={14} />
172	        {t("releases.back")}
173	      </button>
174	
175	      {/* Header */}
176	      <div>
177	        <h1
178	          style={{
179	            fontFamily: "var(--font-raleway)",
180	            fontSize: "24px",
181	            fontWeight: 700,
182	            color: "var(--foreground)",
