258	            className="group/chip inline-flex items-center gap-1.5 rounded px-2 py-0.5 text-[12px] transition-colors hover:bg-mono-bg"
259	            style={{
260	              backgroundColor: source.last_error ? "var(--error-bg)" : "var(--background)",
261	              border: `1px solid ${source.last_error ? "var(--error-border)" : "var(--border)"}`,
262	            }}
263	            title={source.last_error ? `Error: ${source.last_error}` : undefined}
264	          >
265	            <span
266	              className="inline-block h-1.5 w-1.5 rounded-full shrink-0"
267	              style={{ backgroundColor: source.last_error ? "var(--error-text)" : source.enabled ? "var(--status-completed)" : "var(--text-muted)" }}
268	            />
269	            {(() => { const Icon = getProviderIcon(source.provider); return Icon ? <Icon size={12} className="shrink-0 text-text-muted" /> : null; })()}
270	            <span className="text-secondary-foreground" style={{ fontFamily: "'JetBrains Mono', monospace" }}>
271	              {source.repository}
272	            </span>
273	            {source.last_polled_at && (
274	              <span className="text-text-muted">
275	                {timeAgo(source.last_polled_at).replace(" ago", "")}
276	              </span>
277	            )}
278	            <Pencil className="h-2.5 w-2.5 hidden group-hover/chip:inline shrink-0 text-text-muted opacity-50" />
279	          </button>
280	        ))}
281	        <button
282	          onClick={() => setSourceCreateOpen(true)}
283	          className="inline-flex items-center gap-1 px-2 py-0.5 text-[12px] font-medium rounded border transition-colors hover:bg-mono-bg border-border text-text-muted"
284	          style={{
285	            fontFamily: "var(--font-dm-sans)",
286	          }}
287	        >
288	          <Plus className="h-3 w-3" />
289	          {t("projects.addSource")}
290	        </button>
291	      </div>
292	
293	      {/* Releases flow */}
294	      {releases.length > 0 && (
295	        <FlowSection label={t("projects.releases")} moreHref={`/releases?project=${project.id}`} moreLabel={t("projects.more")}>
296	          {releases.map((r) => {
297	            const src = sourceMap.get(r.source_id);
298	            return (
299	              <span key={r.id} className="inline-flex items-baseline mr-2.5">
300	                <Link
301	                  href={`/releases/${r.id}`}
302	                  className={r.excluded ? "" : "text-[#2563eb] hover:underline"}
303	                  style={{
304	                    fontFamily: "'JetBrains Mono', monospace",
305	                    fontSize: "12px",
306	                    ...(r.excluded ? { color: "var(--text-muted)" } : {}),
307	                  }}
308	                >
309	                  {r.version}
310	                </Link>
311	                {!r.excluded && r.semantic_release_status === "completed" && r.semantic_release_id && (() => {
312	                  return r.semantic_release_urgency ? (
313	                    <Link
314	                      href={`/projects/${project.id}/semantic-releases/${r.semantic_release_id}`}
315	                      className="ml-1 transition-colors"
316	                      title={`${r.semantic_release_urgency} — ${t("projects.viewReport")}`}
317	                    >
318	                      <UrgencyPill urgency={r.semantic_release_urgency} variant="icon-only" />
319	                    </Link>
320	                  ) : (
321	                    <Link
322	                      href={`/projects/${project.id}/semantic-releases/${r.semantic_release_id}`}
323	                      className="inline-flex items-center gap-0.5 rounded-full px-2 py-0.5 ml-1 text-[10px] font-semibold transition-colors bg-muted text-text-secondary"
324	                      style={{ border: "1px solid rgba(107,114,128,0.18)", fontFamily: "var(--font-dm-sans)" }}
325	                      title={t("projects.viewReport")}
326	                    >
327	                      {t("projects.report")}
328	                    </Link>
329	                  );
330	                })()}
331	                {!r.excluded && (r.semantic_release_status === "pending" || r.semantic_release_status === "processing") && (
332	                  <span
333	                    className="inline-flex items-center gap-0.5 rounded px-1 py-0.5 ml-1 text-[10px]"
334	                    style={{ backgroundColor: "#fef9c3", color: "#92400e", fontFamily: "var(--font-dm-sans)" }}
335	                  >
336	                    <Loader2 size={10} className="animate-spin" />
337	                  </span>
338	                )}
339	                {src && (
340	                  <span
341	                    className="text-[11px] ml-1 hidden sm:inline text-text-muted"
342	                    style={r.excluded ? { opacity: 0.5 } : {}}
343	                  >
344	                    ({src.repository.split("/").pop()})
345	                  </span>
346	                )}
347	                <span
348	                  className="text-[11px] ml-1 text-text-muted"
349	                  style={r.excluded ? { opacity: 0.5 } : {}}
350	                >
351	                  {timeAgo(r.released_at || r.created_at).replace(" ago", "")}
352	                </span>
353	              </span>
354	            );
355	          })}
356	        </FlowSection>
357	      )}
358	
359	      {/* Add Source dialog */}
360	      <Dialog open={sourceCreateOpen} onOpenChange={setSourceCreateOpen}>
361	        <DialogContent className="sm:max-w-lg">
362	          <DialogHeader>
363	            <DialogTitle>{t("projects.addSource")}</DialogTitle>
364	          </DialogHeader>
365	          <SourceForm
366	            title={t("projects.addSource")}
367	            projectId={project.id}
368	            onSubmit={async (input) => {
369	              const res = await sourcesApi.create(project.id, input);
370	              if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
371	            }}
372	            onSuccess={() => {
373	              setSourceCreateOpen(false);
374	              mutateSources();
375	            }}
376	            onCancel={() => setSourceCreateOpen(false)}
377	          />
378	        </DialogContent>
379	      </Dialog>
380	
381	      {/* Edit Source dialog */}
382	      <Dialog
383	        open={!!editingSource}
384	        onOpenChange={(open) => { if (!open) setEditingSource(null); }}
385	      >
386	        <DialogContent className="sm:max-w-lg">
387	          <DialogHeader>
388	            <DialogTitle>{t("projects.editSource")}</DialogTitle>
389	          </DialogHeader>
390	          {editingSource && (
391	            <SourceForm
392	              key={editingSource.id}
393	              title={t("projects.editSource")}
394	              initial={editingSource}
395	              onSubmit={async (input) => {
396	                await sourcesApi.update(editingSource.id, input);
397	              }}
398	              onSuccess={() => {
399	                setEditingSource(null);
400	                mutateSources();
401	              }}
402	              onCancel={() => setEditingSource(null)}
403	            />
404	          )}
405	        </DialogContent>
406	      </Dialog>
407	    </div>
408	  );
409	}
