413	function ProjectCompactRow({ project }: { project: Project }) {
414	  const { t } = useTranslation();
415	  const router = useRouter();
416	  const { data: relData } = useSWR(`project-${project.id}-card-releases`, () =>
417	    releasesApi.listByProject(project.id, 1, 5, { include_excluded: true })
418	  );
419	  const { data: srcData } = useSWR(`project-${project.id}-card-sources`, () =>
420	    sourcesApi.listByProject(project.id)
421	  );
422	  const { data: srData } = useSWR(`project-${project.id}-card-sr`, () =>
423	    srApi.list(project.id, 1, 3)
424	  );
425	
426	  const releases = relData?.data ?? [];
427	  const sources = srcData?.data ?? [];
428	  const srItems = srData?.data ?? [];
429	  const latest = releases[0];
430	  const latestSr = srItems[0];
431	
432	  const sourceMap = useMemo(() => {
433	    const m = new Map<string, Source>();
434	    for (const s of sources) m.set(s.id, s);
435	    return m;
436	  }, [sources]);
437	
438	  const latestSrc = latest ? sourceMap.get(latest.source_id) : undefined;
439	  const latestIcon = latestSrc ? getProviderIcon(latestSrc.provider) : undefined;
440	
441	  return (
442	    <div
443	      onClick={() => router.push(`/projects/${project.id}`)}
444	      className="flex items-center gap-4 rounded-md px-4 py-2.5 transition-colors hover:bg-background cursor-pointer bg-surface"
445	      style={{ border: "1px solid var(--border)" }}
446	    >
447	      {/* Project name */}
448	      <span
449	        className="flex items-center gap-2 text-[14px] font-bold shrink-0 text-beacon-accent"
450	        style={{ fontFamily: "var(--font-raleway)", minWidth: "160px" }}
451	      >
452	        <ProjectLogo name={project.name} sources={sources} size={24} />
453	        {project.name}
454	      </span>
455	
456	      {/* Latest release */}
457	      <span className="flex items-center gap-1.5 shrink-0" style={{ minWidth: "140px" }}>
458	        {latest ? (
459	          <>
460	            <Link
461	              href={`/releases/${latest.id}`}
462	              onClick={(e) => e.stopPropagation()}
463	              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none hover:ring-1 hover:ring-border transition-shadow bg-mono-bg text-secondary-foreground"
464	              style={{
465	                fontFamily: "'JetBrains Mono', monospace",
466	              }}
467	            >
468	              {latest.version}
469	            </Link>
470	            {latestIcon && latestIcon({ size: 12, className: "shrink-0 text-text-muted" })}
471	            {latestSr?.status === "completed" && (() => {
472	              return latestSr.report?.urgency ? (
473	                <Link
474	                  href={`/projects/${project.id}/semantic-releases/${latestSr.id}`}
475	                  onClick={(e) => e.stopPropagation()}
476	                  className="transition-colors"
477	                  title={`${latestSr.report!.urgency} — ${t("projects.viewReport")}`}
478	                >
479	                  <UrgencyPill urgency={latestSr.report!.urgency} variant="icon-only" />
480	                </Link>
481	              ) : (
482	                <Link
483	                  href={`/projects/${project.id}/semantic-releases/${latestSr.id}`}
484	                  onClick={(e) => e.stopPropagation()}
485	                  className="inline-flex items-center gap-0.5 rounded-full px-2 py-0.5 text-[10px] font-semibold transition-colors bg-muted text-text-secondary"
486	                  style={{ border: "1px solid rgba(107,114,128,0.18)", fontFamily: "var(--font-dm-sans)" }}
487	                  title={t("projects.viewReport")}
488	                >
489	                  {t("projects.report")}
490	                </Link>
491	              );
492	            })()}
493	            {(latestSr?.status === "pending" || latestSr?.status === "processing") && (
494	              <span
495	                className="inline-flex items-center gap-0.5 rounded px-1.5 py-0.5 text-[10px]"
496	                style={{ backgroundColor: "#fef9c3", color: "#92400e", fontFamily: "var(--font-dm-sans)" }}
497	              >
498	                <Loader2 size={10} className="animate-spin" />
499	              </span>
500	            )}
501	          </>
502	        ) : (
503	          <span className="text-[12px] italic text-text-muted">
504	            {t("projects.noReleases")}
505	          </span>
506	        )}
507	      </span>
508	
509	      {/* Summary */}
510	      <span className="flex items-center gap-1.5 flex-1 min-w-0">
511	        {latestSr?.status === "completed" ? (
512	          <>
513	            {latestSr.report?.urgency && (
514	              <UrgencyPill urgency={latestSr.report.urgency} variant="text" className="shrink-0" />
515	            )}
516	            {latestSr.report?.summary && (
