518	                {latestSr.report.summary.length > 60
519	                  ? latestSr.report.summary.slice(0, 60) + "\u2026"
520	                  : latestSr.report.summary}
521	              </span>
522	            )}
523	          </>
524	        ) : (
525	          <span className="text-[12px] italic text-text-muted">
526	            {latestSr ? latestSr.status : t("projects.noAnalysis")}
527	          </span>
528	        )}
529	      </span>
