538	
539	export default function ProjectsPage() {
540	  const { t } = useTranslation();
541	  const [createOpen, setCreateOpen] = useState(false);
542	  const [viewMode, setViewMode] = useState<"cards" | "compact">("cards");
543	  const [search, setSearch] = useState("");
544	  const [sortBy, setSortBy] = useState<"updated" | "added" | "name">("updated");
545	  const [page, setPage] = useState(1);
546	  const { data, isLoading } = useSWR("projects", () => projectsApi.list(1, 100));
547	  const items = data?.data ?? [];
548	
549	  const PAGE_SIZE = 12;
550	  const filtered = search
551	    ? items.filter((p) => p.name.toLowerCase().includes(search.toLowerCase()))
552	    : items;
553	  const sorted = useMemo(() => {
554	    const arr = [...filtered];
555	    switch (sortBy) {
556	      case "updated":
557	        return arr.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
558	      case "added":
559	        return arr.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
560	      case "name":
561	        return arr.sort((a, b) => a.name.localeCompare(b.name));
562	    }
563	  }, [filtered, sortBy]);
564	  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));
565	  const currentPage = Math.min(page, totalPages);
566	  const paged = sorted.slice((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE);
567	
568	  return (
569	    <div className="flex flex-col gap-4 fade-in">
570	      <div className="flex items-center justify-between">
571	        <div>
572	          <h1
573	            className="text-foreground"
574	            style={{
575	              fontFamily: "var(--font-raleway)",
576	              fontSize: "24px",
577	              fontWeight: 700,
578	            }}
579	          >
580	            {t("projects.title")}
581	          </h1>
582	          <p
583	            className="mt-1 text-[13px] text-text-secondary inline-flex items-center gap-1"
584	            style={{ fontFamily: "var(--font-dm-sans)" }}
585	          >
586	            {t("projects.description")}
587	            <UrgencyLegend />
588	          </p>
589	        </div>
590	        <div className="flex items-center gap-2">
591	          <div className="relative">
592	            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-text-muted" />
593	            <input
594	              type="text"
595	              value={search}
596	              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
597	              placeholder={t("projects.searchPlaceholder")}
598	              className="rounded-md border py-1.5 pl-8 pr-3 text-[13px] w-48 border-border text-secondary-foreground bg-surface"
599	              style={{ fontFamily: "var(--font-dm-sans)" }}
600	            />
601	          </div>
602	          <div className="flex items-center gap-1.5 rounded-md border px-2.5 py-1.5 text-[13px] border-border text-secondary-foreground" style={{ fontFamily: "var(--font-dm-sans)" }}>
603	            <ArrowUpDown className="h-3.5 w-3.5 shrink-0 text-text-muted" />
604	            <select
605	              value={sortBy}
606	              onChange={(e) => { setSortBy(e.target.value as "updated" | "added" | "name"); setPage(1); }}
607	              className="bg-transparent outline-none cursor-pointer text-[13px] text-secondary-foreground"
608	              style={{ fontFamily: "var(--font-dm-sans)" }}
609	            >
610	              <option value="updated">{t("projects.sortUpdated")}</option>
611	              <option value="added">{t("projects.sortAdded")}</option>
612	              <option value="name">{t("projects.sortName")}</option>
613	            </select>
614	          </div>
615	          <div className="flex items-center rounded-md border border-border">
616	            <button
617	              onClick={() => setViewMode("cards")}
618	              className="p-1.5 rounded-l-md transition-colors"
619	              style={{
620	                backgroundColor: viewMode === "cards" ? "var(--mono-bg)" : "transparent",
621	                color: viewMode === "cards" ? "var(--foreground)" : "var(--text-muted)",
622	              }}
623	              title={t("projects.cardView")}
624	            >
625	              <LayoutGrid className="h-4 w-4" />
626	            </button>
627	            <button
628	              onClick={() => setViewMode("compact")}
629	              className="p-1.5 rounded-r-md transition-colors"
630	              style={{
631	                backgroundColor: viewMode === "compact" ? "var(--mono-bg)" : "transparent",
632	                color: viewMode === "compact" ? "var(--foreground)" : "var(--text-muted)",
633	              }}
634	              title={t("projects.compactView")}
635	            >
636	              <List className="h-4 w-4" />
637	            </button>
638	          </div>
639	          <div className="h-5 w-px bg-border mx-1" />
640	          <button
641	            onClick={() => setCreateOpen(true)}
642	            className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90 bg-beacon-accent"
643	            style={{ fontFamily: "var(--font-dm-sans)" }}
644	          >
645	            <Plus className="h-3.5 w-3.5" />
646	            {t("projects.newProject")}
647	          </button>
648	        </div>
649	      </div>
650	
651	      {isLoading ? (
652	        <p
653	          className="px-4 py-8 text-center text-[14px] italic text-text-muted"
654	          style={{ fontFamily: "var(--font-raleway)" }}
655	        >
656	          {t("projects.loading")}
657	        </p>
658	      ) : items.length === 0 ? (
659	        <div
660	          className="flex flex-col items-center justify-center rounded-md border py-12 border-border bg-surface"
661	        >
662	          <p
663	            className="text-[14px] italic text-text-muted"
664	            style={{ fontFamily: "var(--font-raleway)" }}
665	          >
666	            {t("projects.empty")}
667	          </p>
668	          <button
669	            onClick={() => setCreateOpen(true)}
670	            className="mt-4 flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90 bg-beacon-accent"
671	            style={{ fontFamily: "var(--font-dm-sans)" }}
672	          >
673	            <Plus className="h-3.5 w-3.5" />
674	            {t("projects.newProject")}
675	          </button>
676	        </div>
677	      ) : filtered.length === 0 ? (
678	        <p
679	          className="px-4 py-8 text-center text-[14px] italic text-text-muted"
680	          style={{ fontFamily: "var(--font-raleway)" }}
681	        >
682	          {t("projects.noMatch").replace("{search}", search)}
683	        </p>
684	      ) : (
685	        <>
686	          <div className={viewMode === "cards" ? "space-y-5" : "space-y-1.5"}>
687	            {paged.map((project) =>
688	              viewMode === "cards" ? (
689	                <ProjectFlowCard key={project.id} project={project} />
690	              ) : (
691	                <ProjectCompactRow key={project.id} project={project} />
692	              )
693	            )}
694	          </div>
695	          {totalPages > 1 && (
696	            <div className="flex items-center justify-center gap-3 pt-2">
697	              <button
698	                onClick={() => setPage((p) => Math.max(1, p - 1))}
699	                disabled={currentPage <= 1}
700	                className="rounded-md border px-3 py-1 text-[13px] transition-colors disabled:opacity-40 border-border text-secondary-foreground"
701	                style={{ fontFamily: "var(--font-dm-sans)" }}
702	              >
703	                {t("projects.previous")}
704	              </button>
705	              <span
706	                className="text-[13px] text-text-secondary"
707	                style={{ fontFamily: "var(--font-dm-sans)" }}
708	              >
709	                {t("projects.page").replace("{current}", String(currentPage)).replace("{total}", String(totalPages))}
710	              </span>
711	              <button
712	                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
713	                disabled={currentPage >= totalPages}
714	                className="rounded-md border px-3 py-1 text-[13px] transition-colors disabled:opacity-40 border-border text-secondary-foreground"
715	                style={{ fontFamily: "var(--font-dm-sans)" }}
716	              >
717	                {t("projects.next")}
718	              </button>
719	            </div>
720	          )}
721	        </>
722	      )}
723	
724	      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
725	        <DialogContent className="sm:max-w-lg">
726	          <DialogHeader>
727	            <DialogTitle>{t("projects.createProject")}</DialogTitle>
728	          </DialogHeader>
729	          <ProjectForm
730	            title={t("projects.createProject")}
731	            onSubmit={async (result) => {
732	              const created = await projectsApi.create(result.project);
733	              if (result.source && created.data?.id) {
734	                const res = await sourcesApi.create(created.data.id, result.source);
735	                if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
736	              }
737	            }}
738	            onSuccess={() => { setCreateOpen(false); mutate("projects"); }}
739	            onCancel={() => setCreateOpen(false)}
740	          />
741	        </DialogContent>
742	      </Dialog>
743	    </div>
744	  );
745	}
